<span class="line"><span class="token keyword">export</span> <span class="token keyword">const</span> <span class="token constant">API_VERSION_KEY</span> <span class="token operator">=</span> <span class="token string">&#39;apiVersion&#39;</span><span class="token punctuation">;</span></span>
